1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_THRESHOLD = 5;
5	const HIGH_ENCHANTMENT_RATE = 0.3;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const LOYALTY_RATE = 0.2;
8	const FOLLOW_UP_RATE = 0.15;
9	const BLOCK_SIZE = 3;
10	const BLOCK_PREMIUM = 60;
11	const DEDUCTIBLE = 100;
12	const CAP_MULTIPLIER = 2;
13	
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const INSURANCE_VALUE: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	type Item = {
33	  type: string;
34	  material?: string;
35	  enchantment?: number;
36	  cursed?: boolean;
37	};
38	type Damage = { itemType: string; amount: number };
39	type Incident = { cause: string; damages: Damage[] };
40	type QuoteStep = { op: "quote"; items: Item[] };
41	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
42	type Step = QuoteStep | ClaimStep;
43	type Customer = { yearsWithMHPCO: number };
44	type Scenario = { customer: Customer; steps: Step[] };
45	type QuoteResult = { premium: number };
46	type ClaimResult = { payout: number; remainingCap: number };
47	type StepResult = QuoteResult | ClaimResult;
48	type ScenarioOutput = { results: StepResult[] };
49	
50	type Policy = { items: Item[]; remainingCap: number };
51	
52	const groupCountsByType = (items: Item[]): Map<string, number> => {
53	  const counts = new Map<string, number>();
54	  for (const { type } of items) {
55	    counts.set(type, (counts.get(type) ?? 0) + 1);
56	  }
57	  return counts;
58	};
59	
60	const basePremiumForGroup = (type: string, count: number): number => {
61	  if (!(type in BASE_PREMIUM)) {
62	    throw new Error(`unknown item type: ${type}`);
63	  }
64	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
65	  return count * BASE_PREMIUM[type];
66	};
67	
68	const basePremiumFor = (items: Item[]): number =>
69	  Array.from(groupCountsByType(items)).reduce(
70	    (total, [type, count]) => total + basePremiumForGroup(type, count),
71	    0,
72	  );
73	
74	const curseSurchargeFor = (item: Item): number =>
75	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_RATE : 0;
76	
77	const highEnchantmentSurchargeFor = (item: Item): number =>
78	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
79	    ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_RATE
80	    : 0;
81	
82	const ITEM_SURCHARGES: Array<(item: Item) => number> = [
83	  curseSurchargeFor,
84	  highEnchantmentSurchargeFor,
85	];
86	
87	const surchargesForItem = (item: Item): number =>
88	  ITEM_SURCHARGES.reduce((sum, surcharge) => sum + surcharge(item), 0);
89	
90	const itemSurchargesFor = (items: Item[]): number =>
91	  items.reduce((sum, item) => sum + surchargesForItem(item), 0);
92	
93	const firstInsuranceSurchargeFor = (basePremium: number): number =>
94	  basePremium * FIRST_INSURANCE_RATE;
95	
96	const loyaltyDiscountFor = (basePremium: number, customer: Customer): number =>
97	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
98	    ? basePremium * LOYALTY_RATE
99	    : 0;
100	
101	const followUpDiscountFor = (basePremium: number, isFollowUp: boolean): number =>
102	  isFollowUp ? basePremium * FOLLOW_UP_RATE : 0;
103	
104	const premiumFor = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
105	  const basePremium = basePremiumFor(items);
106	  const surcharges =
107	    itemSurchargesFor(items) + firstInsuranceSurchargeFor(basePremium);
108	  const discounts =
109	    loyaltyDiscountFor(basePremium, customer) +
110	    followUpDiscountFor(basePremium, isFollowUp);
111	  return Math.ceil(basePremium + surcharges - discounts + PROCESSING_FEE);
112	};
113	
114	const quoteStep = (
115	  { items }: QuoteStep,
116	  customer: Customer,
117	  isFollowUp: boolean,
118	): QuoteResult => ({
119	  premium: premiumFor(items, customer, isFollowUp),
120	});
121	
122	const insuranceSumFor = (items: Item[]): number =>
123	  items.reduce((sum, { type }) => sum + INSURANCE_VALUE[type], 0);
124	
125	const payoutForDamage = ({ amount }: Damage): number =>
126	  Math.max(0, amount - DEDUCTIBLE);
127	
128	const claimStep = (
129	  { policy: policyIndex, incident }: ClaimStep,
130	  policies: Policy[],
131	): ClaimResult => {
132	  const policy = policies[policyIndex];
133	  const grossPayout = incident.damages.reduce(
134	    (sum, damage) => sum + payoutForDamage(damage),
135	    0,
136	  );
137	  const payout = Math.min(grossPayout, policy.remainingCap);
138	  policy.remainingCap -= payout;
139	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
140	};
141	
142	export const runScenario = (input: Scenario): ScenarioOutput => {
143	  const policies: Policy[] = [];
144	  let quoteCount = 0;
145	  const results: StepResult[] = input.steps.map((step) => {
146	    if (step.op === "quote") {
147	      const isFollowUp = quoteCount > 0;
148	      quoteCount += 1;
149	      policies.push({
150	        items: step.items,
151	        remainingCap: insuranceSumFor(step.items) * CAP_MULTIPLIER,
152	      });
153	      return quoteStep(step, input.customer, isFollowUp);
154	    }
155	    return claimStep(step, policies);
156	  });
157	  return { results };
158	};
