export const runScenario = (input: Scenario): ScenarioOutput => {
  const policies: Policy[] = [];
  let quoteCount = 0;
  const results: StepResult[] = input.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = quoteCount > 0;
      quoteCount += 1;
      policies.push({
        items: step.items,
        remainingCap: insuranceSumFor(step.items) * CAP_MULTIPLIER,
      });
      return quoteStep(step, input.customer, isFollowUp);
    }
    return claimStep(step, policies);
  });
  return { results };
};

